import { useState,useEffect } from "react";
import {Link} from 'react-router-dom';
import axios from 'axios';
export default function Utilisateur(){
    const [users,setUsers] = useState([]);
    const [infos,setInfos] = useState([]);
    const token = localStorage.getItem("token");
    const [username,setUsername] = useState('');
    const getUsers = async () => {
        const res = await axios.get('http://localhost:3001/users', {
          headers: { Authorization: `Bearer ${token}`}
        });
        setUsers(res.data);
    }
    useEffect(() => {
        getUsers();
    },[]);
    const nas = infos.length > 0 ? infos : users;
    return (
        <>
            <Link to='/AjouterUtilisateur'>Ajouter un utilisateur</Link>
                <input type="text" value={username} onChange={(e) => setUsername(e.target.value)}/>
                <button onClick={async() => {
                    try {
                        const res = await axios.get(`http://localhost:3001/searchUsername/${username}`, {
                            headers: { Authorization: `Bearer ${token}`}
                        });
                        setInfos(res.data);
                    } catch (error) {
                        console.error("Search error:", error);
                        alert("Search failed: " + (error.response?.data?.message || error.message));
                    }
                }}>search</button>
            <center>
                <table border='1'>
                <tr>
                    <th>name</th>
                    <th>email</th>
                    <th>role</th>
                    <th>actions</th>
                </tr>
                {nas.map((u,i) => (
                    <tr key={i}>
                        <td>{u.username}</td>
                        <td>{u.email}</td>
                        <td>{u.role}</td>
                        <td>
                            <button onClick={ async () => {
                                await axios.delete(`http://localhost:3001/delete/${u._id}`,{
                                headers: { Authorization: `Bearer ${token}` }
                                })
                                setUsers(prev => prev.filter(user => user._id !== u._id));
                            }}>supprimer</button>
                            <Link to={`/modifierUtilisateur/${u._id}`}>modifier</Link>             
                            </td>
                        {/* <td><Link to={`/details/${u._id}`}>details</Link></td> */}
                    </tr>
                ))}
                 </table>
            </center>
           

        </>
    )
    
}
